-- 로컬/데모용 더미데이터입니다.
--
-- 원본:
--   38-SOPT-Collaboration-Korail Google Sheet
--
-- 로컬 실행 방법:
--   1. docker compose로 로컬 MySQL을 실행합니다.
--   2. Spring 애플리케이션을 한 번 실행해서 Hibernate가 테이블을 만들게 합니다.
--   3. 프로젝트 루트에서 scripts/reset-local-db-to-seed.sh를 실행합니다.
--
-- 원격 데모 DB 초기화:
--   GitHub Actions의 "Reset Demo DB" workflow를 수동 실행합니다.
--
-- 주의사항:
--   - 외래키 의존 순서에 맞춰 train_types -> schedules -> reservation_seats 순서로 넣습니다.
--   - ON DUPLICATE KEY UPDATE를 사용해서 같은 seed를 여러 번 실행해도 실패하지 않게 했습니다.
--   - reservation_seats 테이블에는 같은 스케줄의 같은 좌석을 중복 예약하지 못하도록
--     (schedule_id, seat_number) 유니크 제약이 있어야 합니다.

ON DUPLICATE KEY UPDATE
    train_name = VALUES(train_name),
    general_price = VALUES(general_price),
    special_price = VALUES(special_price),
    outlet_seat_numbers = VALUES(outlet_seat_numbers);

ON DUPLICATE KEY UPDATE
    train_type_id = VALUES(train_type_id),
    train_name = VALUES(train_name),
    departure_time = VALUES(departure_time),
    arrival_time = VALUES(arrival_time),
    created_at = VALUES(created_at),
    updated_at = VALUES(updated_at);

ON DUPLICATE KEY UPDATE
    schedule_id = VALUES(schedule_id),
    user_id = VALUES(user_id),
    seat_number = VALUES(seat_number),
    created_at = VALUES(created_at),
    updated_at = VALUES(updated_at);
